// Determine file type and add metadata
const fileName = $binary && $binary.file && $binary.file.fileName ? $binary.file.fileName : ($json.message && $json.message.document && $json.message.document.file_name ? $json.message.document.file_name : 'uploaded');
const lower = fileName.toLowerCase();
const isZip = lower.endsWith('.zip');
const isPdf = lower.endsWith('.pdf');

return [{
  json: {
    fileName,
    isZip,
    isPdf,
    telegramChatId: $json.message && $json.message.chat ? $json.message.chat.id : ($json.message && $json.message.from ? $json.message.from.id : null),
    telegramUsername: $json.message && $json.message.from ? $json.message.from.username : null,
  },
  binary: $binary
}];

// This node expects the Extract ZIP step to write files to /tmp/n8n_extract/extracted
const fs = require('fs');
const path = '/tmp/n8n_extract/extracted';
let out = [];
function walk(dir) {
  const items = fs.readdirSync(dir);
  for (const it of items) {
    const p = dir + '/' + it;
    const stat = fs.statSync(p);
    if (stat.isDirectory()) walk(p);
    else {
      const data = fs.readFileSync(p);
      out.push({
        json: { fileName: it, path: p },
        binary: { file: { data: data.toString('base64'), fileName: it, mimeType: '' } }
      });
    }
  }
}
if (fs.existsSync(path)) walk(path);
return out;

const text = $json.text || ($json.body && $json.body.text) || '';
// Try to extract name patterns
let studentName = $json.fileName ? $json.fileName.replace(/\.[^/.]+$/, '') : 'Unknown';
const m = text.match(/(?:Name|Student)[:\-\s]*([A-Z][a-z]+(?:\s[A-Z][a-z]+)*)/i);
if (m) studentName = m[1].trim();
return [{ json: { text, studentName, fileName: $json.fileName } }];

// Parse model response and return one item per Q/A
const content = $json.choices ? $json.choices[0].message.content : ($json.body && $json.body.choices && $json.body.choices[0] && $json.body.choices[0].message && $json.body.choices[0].message.content ? $json.body.choices[0].message.content : $json.content || '');
let arr = [];
try {
  arr = JSON.parse(content);
} catch(e) {
  const m = content.match(/(\[.*\])/s);
  if (m) arr = JSON.parse(m[1]);
}
if (!Array.isArray(arr)) arr = [];

const out = arr.map(q => ({
  json: {
    studentName: $json.studentName || $json.fileName,
    fileName: $json.fileName,
    question_id: q.question_id || null,
    question: q.question || '',
    answer: q.answer || '',
    page: q.page || null
  }
}));
return out;

// This node assumes all Q/A items for a single PDF are in this execution
const itemsArr = items;
const groups = {};
for (const it of itemsArr) {
  const key = it.json.fileName || it.json.studentName || 'unknown';
  if (!groups[key]) groups[key] = { studentName: it.json.studentName, fileName: key, questions: [] };
  groups[key].questions.push({
    question_id: it.json.question_id,
    question: it.json.question,
    answer: it.json.answer,
    page: it.json.page
  });
}
const out = Object.values(groups).map(g => ({ json: g }));
return out;

