// Parse grader response, merge with questions to create final report
const resp = $json.choices ? $json.choices[0].message.content : ($json.body && $json.body.choices ? $json.body.choices[0].message.content : $json.content || '');
let parsed = {};
try { parsed = JSON.parse(resp); } catch(e) {
  const m = resp.match(/(\{.*\})/s);
  parsed = m ? JSON.parse(m[1]) : {};
}
const results = parsed.results || [];
const questions = $json.questions || [];
const merged = questions.map(q => {
  const r = results.find(x => x.question_id == q.question_id) || {};
  return {
    question_id: q.question_id,
    question: q.question,
    answer: q.answer,
    score: r.score || 0,
    feedback: r.feedback || ''
  };
});
const total = parsed.total_score || merged.reduce((s,i)=>s+(i.score||0),0);
const overall = parsed.overall_summary || (total/ (merged.length*10) >= 0.8 ? 'Good understanding' : 'Needs improvement');

return [{ json: {
  studentName: $json.studentName,
  fileName: $json.fileName,
  questions: merged,
  total,
  maxScore: merged.length * 10,
  overall
}}];
